// 加载搜索数据
fetch('/search.json')
  .then(response => response.json())
  .then(data => {
    // 初始化Lunr索引
    const idx = lunr(function () {
      this.field('title', { boost: 10 });
      this.field('content');
      this.ref('id');

      data.forEach(item => this.add(item));
    });

    // 搜索函数示例
    function search(query) {
      const result = idx.search(query);
      // 处理结果，展示给用户
      console.log(result);
      // 这里可以进一步实现结果的渲染
    }
  });


# Doris坏盘换盘方法

## 先换好盘
参考其它/data，创建好目录，正确授权。
```
cd /
mkdir -p /doris-storage
chown -R doris:doris /doris-storage
ll
```

## 注释掉坏盘路径
```
vi /usr/local/doris-be/conf/be_custom.conf
```
![](vx_images/46833146873345.png =628x)
注释掉broken_storage_path。

## 重启be进程
可在Web管理控制台操作。

